class Program
{
    static void Main(string[] args)
    {
        string url = “https://www.example.com”;
        HttpWebRequest request = (HttpWebRequest)WebRequest.Create(url);
        request.Method = “GET”;

        // 创建一个 CookieContainer 对象
        CookieContainer cookieContainer = new CookieContainer();

        // 添加要携带的 Cookie
        Cookie myCookie = new Cookie(“mycookie”, “12345”, “/”, “www.example.com”);
        cookieContainer.Add(myCookie);

        // 将 CookieContainer 对象赋值给 HttpWebRequest 的 CookieContainer 属性
        request.CookieContainer = cookieContainer;

        // 发送 HTTP 请求并接收响应
        HttpWebResponse response = (HttpWebResponse)request.GetResponse();

        // 读取响应中包含的 Cookie
        string responseCookie = response.Headers[“Set-Cookie”];

        // 输出响应内容和接收到的Cookie
        Console.WriteLine(“响应内容:”);
        Console.WriteLine(new StreamReader(response.GetResponseStream()).ReadToEnd());

        Console.WriteLine(“接收到的Cookie:”);
        Console.WriteLine(responseCookie);

        response.Close();
    }
}

可以将该 Cookie 拆分成多个子 Cookie，分别设置到 CookieContainer 中的 CookieCollection 中。可以使用字符串的 Split 方法将该 Cookie 拆分成多个键值对，每个键值对表示一个子 Cookie，如下所示：

```
string cookieString = "MX=session-id=147-5772975-2879858; session-id-time=2082787201l; i18n-prefs=MXN; ubid-acbmx=132-4785117-4628254; session-token=TOolhNfrq5OjiLKaVoudwHlUhzSguc/zWuGFLNJAXAEP0UIyg+POrhoNmxG4QRukSdkn53O4nz4FpXrhXXXVc2oE29rB0t2KSgitgr3SHLRUcn1XF5TOfktTzu1eR2BFf0IiUbazprsagpVtckxIt4qCKiTscqyFzkMtghdh7/+foJAG5Y9NCAo6tIha+RxOkAey/EZHpYszyM45cvFRZil0NcJglpof9xB0eCli9l08ujyYV3fwFLM62oan/Uhr";
string[] cookies = cookieString.Split("; ");

CookieContainer cookieContainer = new CookieContainer();
foreach (string cookie in cookies)
{
    string[] keyValue = cookie.Split('=');
    Cookie subCookie = new Cookie(keyValue[0], keyValue[1]);
    subCookie.Domain = "www.example.com";  // 根据实际域名设置
    cookieContainer.Add(subCookie);
}
```

以上代码将 cookieString 拆分成多个 Cookie，每个子 Cookie 以键值对形式保存在数组 cookies 中。然后通过遍历数组，将每个子 Cookie 添加到 CookieContainer 中的 CookieCollection 中。在具体添加每个子 Cookie 时，需要根据实际的域名设置 Cookie 对象的 Domain 属性。

在 C# 中可以使用 Uri 类的方法来获取 URL 的 domain。具体代码如下：

```csharp
string url = "https://www.example.com/search/?q=keyword";
Uri uri = new Uri(url);
string domain = uri.Host;
Console.WriteLine(domain);  // 输出 "www.example.com"
```

以上代码中，我们先定义了一个包含 URL 的字符串 url，然后使用 Uri 类的构造函数将其转换为 Uri 对象。接着就可以使用 Uri 对象的 Host 属性获取 URL 的 domain。最后使用 Console.WriteLine 方法将 domain 输出到控制台。运行以上代码，输出结果为 "www.example.com"。

需要注意的是，如果 URL 中不包含有效的协议头或域名，则代码可能抛出异常或返回错误的结果。因此在使用 Uri 类时应该先检查 URL 的格式是否正确。

在上面示例代码中，已经使用 CookieContainer 对象将自定义的 Cookie 添加到 HTTP 请求头中发送给服务器，以下是如何将服务器返回的 Cookie 收集到 CookieContainer 中:

```
string url = “https://www.example.com”;
HttpWebRequest request = (HttpWebRequest)WebRequest.Create(url);
request.Method = “GET”;

CookieContainer cookieContainer = new CookieContainer();

request.CookieContainer = cookieContainer;

HttpWebResponse response = (HttpWebResponse)request.GetResponse();

// 此处，将获取到的 Cookie 添加到 CookieContainer 中
foreach (Cookie cookie in response.Cookies)
{
    cookieContainer.Add(cookie);
}

string responseCookie = response.Headers[“Set-Cookie”];

Console.WriteLine(“响应内容:”);
Console.WriteLine(new StreamReader(response.GetResponseStream()).ReadToEnd());

Console.WriteLine("收到服务端的 Cookie 值：");
foreach (Cookie cookie in cookieContainer.GetCookies(new Uri(url)))
{
    Console.WriteLine(cookie.Name + " = " + cookie.Value);
}
response.Close();
```
在获取响应后，我们可以通过循环遍历返回的 Cookie，并使用 Add 方法将它们添加到前面创建的 CookieContainer 对象中。这样，我们就能够将返回的 Cookie UUID 存储到客户端，供后续的 HTTP 请求使用了。同时，我们还可以使用 GetCookies 方法从 CookieContainer 中获取指定的 Cookie。

CookieContainer 中确实同时包含了发送的 Cookie 和接收的 Cookie，我们可以使用 Cookie.Domain 属性来区分它们。发送的 Cookie 和接收的 Cookie 的 Domain 属性不同，前者为请求 URI 的域名，而后者为响应 Set-Cookie 头中指定的域名。因此，我们可以在解析时通过判断 Cookie.Domain 是否与请求 URI 的域名相同来区分它们。

以下是示例代码实现的一种做法：

```csharp
string url = "https://www.example.com";
CookieContainer cookieContainer = new CookieContainer();

// 添加要携带的 Cookie
Cookie myCookie = new Cookie("mycookie", "12345", "/", "www.example.com");
cookieContainer.Add(myCookie);

// 创建 HTTP 请求
HttpWebRequest request = (HttpWebRequest)WebRequest.Create(url);
request.CookieContainer = cookieContainer;

// 发送 HTTP 请求并接收响应
HttpWebResponse response = (HttpWebResponse)request.GetResponse();

// 获取响应中的 Set-Cookie 头
string responseCookieHeader = response.Headers.Get("Set-Cookie");

// 将 Set-Cookie 头解析成 Cookie 对象并添加到 CookieContainer 中
if (!string.IsNullOrEmpty(responseCookieHeader))
{
    string[] cookies = responseCookieHeader.Split(';');
    foreach (string cookie in cookies)
    {
        string[] keyValue = cookie.Split('=');
        Cookie subCookie = new Cookie(keyValue[0].Trim(), keyValue[1].Trim());
        subCookie.Domain = new Uri(url).Host;

        // 判断该 Cookie 是不是接收到的 Cookie（由 Set-Cookie 头返回的）
        if (!subCookie.Domain.Equals(myCookie.Domain, StringComparison.OrdinalIgnoreCase))
        {
            cookieContainer.Add(subCookie);
        }
    }
}

response.Close();
```

在以上代码中，在将响应中的 Set-Cookie 头解析成 Cookie 对象的过程中，通过判断 Cookie 的 Domain 属性是否与请求 URI 的域名相同，若相同则说明该 Cookie 为发送时添加的 Cookie，不做处理；若不同则说明该 Cookie 是通过 Set-Cookie 头返回的，需要添加到 CookieContainer 中进行存储。这样就可以区分发送的 Cookie 和接收的 Cookie 了。

是的，的确存在发送的 Cookie 和接收的 Cookie 的 Domain 属性是相同的情况。在这种情况下，我们需要通过其他方式来区分它们。

一种可行的方法是分别使用发送请求时传递的 URL 和获取响应时返回的 URL 来区分它们。例如，我们可以将发送请求时的 URL 存储在发送的 Cookie 中，然后在获取响应时判断响应中的 Set-Cookie 头返回的 Cookie 是否与该 URL 相同，以此来区分发送的 Cookie 和接收的 Cookie。

以下是示例代码实现的一种做法：

```csharp
string url = "https://www.example.com";
CookieContainer cookieContainer = new CookieContainer();

// 添加要发送的 Cookie，将请求时的 URL 存储在其中
string urlWhenSending = "https://www.example.com/search";
Cookie myCookie = new Cookie("mycookie", "12345", "/", "www.example.com");
myCookie.Domain = new Uri(urlWhenSending).Host;
cookieContainer.Add(myCookie);

// 创建 HTTP 请求
HttpWebRequest request = (HttpWebRequest)WebRequest.Create(url);
request.CookieContainer = cookieContainer;

// 发送 HTTP 请求并接收响应
HttpWebResponse response = (HttpWebResponse)request.GetResponse();

// 获取响应中的 Set-Cookie 头
string responseCookieHeader = response.Headers.Get("Set-Cookie");

// 将 Set-Cookie 头解析成 Cookie 对象并添加到 CookieContainer 中
if (!string.IsNullOrEmpty(responseCookieHeader))
{
    string[] cookies = responseCookieHeader.Split(';');
    foreach (string cookie in cookies)
    {
        string[] keyValue = cookie.Split('=');
        Cookie subCookie = new Cookie(keyValue[0].Trim(), keyValue[1].Trim());
        subCookie.Domain = new Uri(url).Host;

        // 判断该 Cookie 是不是接收到的 Cookie（由 Set-Cookie 头返回的）
        if (!subCookie.Domain.Equals(myCookie.Domain, StringComparison.OrdinalIgnoreCase))
        {
            string urlWhenReceiving = response.ResponseUri.ToString();
            if (urlWhenReceiving.StartsWith(urlWhenSending))
            {
                cookieContainer.Add(subCookie);
            }
        }
    }
}

response.Close();
```

在以上代码中，我们将请求时的 URL 存储在一个变量 urlWhenSending 中，并将其添加到 sendingCookie 中。在获取响应时，我们可以通过 HttpWebResponse 对象的 ResponseUri 属性获取响应中的 URL，并判断该 URL 是否与请求时的 URL 相同。如果相同，则说明响应中的 Set-Cookie 头返回的 Cookie 为接收的 Cookie，可以将其添加到 CookieContainer 中供后续使用。而如果不同，则说明该 Cookie 为发送请求时携带的 Cookie，不做处理。

需要注意的是，此方法仅适用于发送请求时的 URL 与获取响应时返回的 URL 前缀相同的情况。如果不是这种情况，需要根据实际情况来进行判断和处理。
